parameters.text:
=Voici les caractéristiques JSON de l'image : {{ JSON.stringify($json) }}

Analyse et choisis la meilleure stratégie de compression en privilégiant la qualité visuelle.

Réponds UNIQUEMENT avec le JSON demandé.

parameters.jsCode:
const data = $input.first().json;
const f = data.features;

const features_clean = {
  type_image: f.type_image,
  taille_kb: f.metadonnees.taille_kb,
  format_original: f.metadonnees.format,
  entropy: f.features_statistiques.entropy,
  contient_texte: f.ocr.contient_texte,
  ratio_complexite: f.morphologie.ratio_complexite
};

const safe = JSON.stringify(features_clean).replace(/[^\x00-\x7F]/g, "");

return [{ json: JSON.parse(safe) }];

const agent1 = $('Code in JavaScript').first().json;   // Décideur
const agent2 = $input.first().json;                     // Comparateur (AI Agent1)

function extractJSON(raw) {
  if (typeof raw !== "string") return raw || {};
  const match = raw.match(/\{[\s\S]*"format"[\s\S]*\}/);
  if (!match) return {};
  try {
    return JSON.parse(match[0].replace(/\\n/g,' ').replace(/\\"/g,'"').replace(/\s+/g,' '));
  } catch {
    return {
      format: raw.match(/"format":\s*"([^"]+)"/)?.[1] || 'WEBP',
      qualite: parseInt(raw.match(/"qualite":\s*(\d+)/)?.[1] || '85'),
    };
  }
}

const dec1 = agent1; // déjà parsé par Code in JavaScript
const dec2 = extractJSON(agent2.output);

// Choisir la meilleure décision
const score = (d) => {
  const pertinence = (d.pertinence || "").toLowerCase();
  if (pertinence.includes("élev")) return 2;
  if (pertinence.includes("moyen")) return 1;
  return 0;
};

const meilleure = score(dec1) >= score(dec2) ? dec1 : dec2;

return [{
  json: {
    decision_finale: {
      format: (meilleure.format || "WEBP").toUpperCase(),
      qualite: parseInt(meilleure.qualite || meilleure.quality || 85),
      justification: meilleure.justification || ""
    },
    raison: score(dec1) >= score(dec2) ? "Agent Décideur choisi" : "Agent Comparateur choisi",
    detail: { llm1: dec1, llm2: dec2 }
  }
}];

const rawOutput = $input.item.json.output;

function extractJSON(raw) {
  if (typeof raw !== "string") return raw;
  const match = raw.match(/\{[\s\S]*"format"[\s\S]*\}/);
  if (!match) return {};
  try {
    const cleaned = match[0].replace(/\\n/g, ' ').replace(/\\"/g, '"').replace(/\s+/g, ' ');
    return JSON.parse(cleaned);
  } catch {
    return {
      format: raw.match(/"format":\s*"([^"]+)"/)?.[1] || '',
      qualite: parseInt(raw.match(/"qualite":\s*(\d+)/)?.[1] || '0'),
      justification: raw.match(/"justification":\s*"([^"]+)"/)?.[1] || '',
      pertinence: raw.match(/"pertinence":\s*"([^"]+)"/)?.[1] || ''
    };
  }
}

const result = extractJSON(rawOutput);
return { json: result };

// ── Récupérer les outputs de chaque agent ──────────────
const analyste    = $('HTTP Request1').first().json;
const decideur    = $('AI Agent').first().json;
const comparateur = $('comparateur').first().json;
const executeur   = $('HTTP Request').first().json;
const rapporteur  = $('HTTP Request2').first().json;

// ── Parser l'output de l'AI Agent (string → JSON) ──────
function extractJSON(raw) {
  if (typeof raw !== "string") return raw || {};
  const match = raw.match(/\{[\s\S]*"format"[\s\S]*\}/);
  if (!match) return {};
  try {
    return JSON.parse(match[0].replace(/\\n/g,' ').replace(/\\"/g,'"').replace(/\s+/g,' '));
  } catch {
    return {
      format: raw.match(/"format":\s*"([^"]+)"/)?.[1] || '',
      qualite: parseInt(raw.match(/"qualite":\s*(\d+)/)?.[1] || '0'),
      justification: raw.match(/"justification":\s*"([^"]+)"/)?.[1] || '',
      pertinence: raw.match(/"pertinence":\s*"([^"]+)"/)?.[1] || ''
    };
  }
}

const decideurParsed = extractJSON(decideur.output);

// ── Décision finale (depuis comparateur) ───────────────
const decisionFinale = {
  format_choisi: comparateur.decision_finale?.format || decideurParsed.format || "",
  qualite: comparateur.decision_finale?.qualite || decideurParsed.qualite || 85,
  raison: comparateur.raison || "",
  justification: comparateur.detail?.llm2?.justification || decideurParsed.justification || ""
};

// ── Construire réponse complète ─────────────────────────
const response = {
  status:            "success",
  features: analyste.features || analyste || {},

  decision_initiale: {
    format_choisi: decideurParsed.format || "",
    qualite: decideurParsed.qualite || "",
    justification: decideurParsed.justification || ""
  },
  decision_finale:   decisionFinale,
  decision_changee:  decideurParsed.format !== decisionFinale.format_choisi,
  metrics:           rapporteur.metrics || rapporteur || {},
  compressed_b64:    executeur.compressed_b64 || executeur.compressed_image_base64 || "",
  rapport:           rapporteur.rapport || {},
  fichiers:          rapporteur.fichiers || {}
};

console.log("✅ Status:", response.status);
console.log("✅ compressed_b64 length:", response.compressed_b64?.length || 0);
console.log("✅ metrics:", JSON.stringify(response.metrics).substring(0, 100));

return [{ json: response }];

// Récupérer image_base64 depuis le Webhook original
const image_base64 = $('Webhook').first().json.body.image_base64;
const filename     = $('Webhook').first().json.body.filename;
const decision     = $('comparateur').first().json.decision_finale || {};

let format  = (decision.format  || "WEBP").toUpperCase();
let qualite = parseFloat(decision.qualite || 85);
if (qualite <= 1.0) qualite = Math.round(qualite * 100);
else qualite = Math.round(qualite);
if (isNaN(qualite)) qualite = 85;

return [{ json: { image_base64, filename, format, quality: qualite } }];
